select b.id, b.group_id as groupId, g.group_name as groupName, b.owner_user_id as ownerUserId, u.display_name as ownerDisplayName, b.batch_name as batchName, b.status, b.total_count as totalCount, b.ready_count as readyCount, b.warning_count as warningCount, b.rejected_count as rejectedCount, b.avg_readiness_score as avgReadinessScore, b.failure_reason as failureReason, b.approved_by_user_id as approvedByUserId, b.approved_at as approvedAt, b.created_at as createdAt, b.updated_at as updatedAt from document_readiness_batches b inner join groups g on g.id = b.group_id inner join users u on u.id = b.owner_user_id
inner join group_memberships gm on gm.group_id = b.group_id and gm.user_id = #{currentUserId}
where g.status = 'ACTIVE'
and b.group_id = #{query.groupId}
and b.status = #{query.status}
order by b.created_at desc, b.id desc

select b.id, b.group_id as groupId, g.group_name as groupName, b.owner_user_id as ownerUserId, u.display_name as ownerDisplayName, b.batch_name as batchName, b.status, b.total_count as totalCount, b.ready_count as readyCount, b.warning_count as warningCount, b.rejected_count as rejectedCount, b.avg_readiness_score as avgReadinessScore, b.failure_reason as failureReason, b.approved_by_user_id as approvedByUserId, b.approved_at as approvedAt, b.created_at as createdAt, b.updated_at as updatedAt from document_readiness_batches b inner join groups g on g.id = b.group_id inner join users u on u.id = b.owner_user_id
inner join group_memberships gm on gm.group_id = b.group_id and gm.user_id = #{currentUserId}
where b.id = #{batchId} and g.status = 'ACTIVE' limit 1
